; The 'production environment' refers to the environment where the actual application is running, as opposed to development or testing environments; 
; A 'developer or admin' is a user with a role of either 'developer' or 'admin'.

sql:
SELECT COUNT(*) AS total_features_with_id_0
FROM features
WHERE feature_id = 0;

SELECT status
FROM features
WHERE status = 'active';

SELECT SUM(duration) AS total_usage_duration
FROM feature_usage
WHERE user_id = 1;

